import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjDialog } from "./OjDialog";
export { OjDialog };

/**
 * Create an instance of [[OjDialog]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojDialog(driver, By.id('my-oj-dialog'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojDialog(driver: DriverLike, by: By): Promise<OjDialog> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjDialog
  if (!(webEl instanceof OjDialog)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-dialog>`);
  }
  return webEl;
}

register("oj-dialog", OjDialog);
